import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { ArrowLeft, Loader2, CheckCircle, CreditCard, Wallet, Shield, ArrowRight } from 'lucide-react';
import { useTranslation } from 'react-i18next';
import './WalletActions.css';

export default function AddFunds() {
  const { t } = useTranslation();
  const navigate = useNavigate();
  
  const [amount, setAmount] = useState('');
  const [paymentMethod, setPaymentMethod] = useState('card');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState(false);
  const [addedAmount, setAddedAmount] = useState(0);

  const quickAmounts = [100, 500, 1000, 2000];
  const paymentMethods = [
    { id: 'card', label: 'Credit/Debit Card', icon: CreditCard },
    { id: 'upi', label: 'UPI / GPay / Paytm', icon: Wallet },
    { id: 'netbanking', label: 'Net Banking', icon: Shield },
  ];

  const handleAddFunds = async () => {
    setError('');
    const numericAmount = parseFloat(amount);
    
    if (!amount || isNaN(numericAmount) || numericAmount <= 0) {
      setError('Please enter a valid amount');
      return;
    }
    if (numericAmount < 10) {
      setError('Minimum amount is ₹10');
      return;
    }
    if (!paymentMethod) {
      setError('Please select a payment method');
      return;
    }

    setLoading(true);
    try {
      await new Promise((res) => setTimeout(res, 1800));
      setAddedAmount(numericAmount);
      setSuccess(true);
    } catch (err) {
      setError('Payment failed. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const handleKeyPress = (e) => {
    if (e.key === 'Enter' && !loading && !success) handleAddFunds();
  };

  // ✅ SUCCESS STATE
  if (success) {
    return (
      <div className="wallet-action-page">
        <div className="wallet-action-container">
          <div className="wallet-action-header">
            <button onClick={() => navigate('/wallet')} className="icon-btn" aria-label="Back to wallet">
              <ArrowLeft size={20} />
            </button>
            <h2>Payment Successful</h2>
          </div>

          <div className="success-card">
            <div className="success-icon">
              <CheckCircle size={48} />
            </div>
            <h3>₹{addedAmount.toFixed(2)} Added!</h3>
            <p className="success-message">Your wallet has been credited successfully. Start shopping now!</p>
            
            <div className="success-details">
              <div className="success-row">
                <span>Transaction ID</span>
                <strong>TXN{Date.now().toString().slice(-8)}</strong>
              </div>
              <div className="success-row">
                <span>Payment Method</span>
                <strong>{paymentMethods.find(m => m.id === paymentMethod)?.label}</strong>
              </div>
              <div className="success-row">
                <span>Time</span>
                <strong>{new Date().toLocaleTimeString()}</strong>
              </div>
            </div>
          </div>

          <div className="success-actions">
            <button className="primary-btn" onClick={() => navigate('/products')}>
              <span>Continue Shopping</span>
              <ArrowRight size={18} />
            </button>
            <button className="secondary-btn" onClick={() => navigate('/wallet')}>
              View Wallet Balance
            </button>
          </div>

          <div className="security-note">
            <Shield size={14} />
            <span>Secured by 256-bit SSL encryption</span>
          </div>
        </div>
      </div>
    );
  }

  // ✅ FORM STATE
  return (
    <div className="wallet-action-page">
      <div className="wallet-action-container">
        {/* Header */}
        <div className="wallet-action-header">
          <button onClick={() => navigate('/wallet')} className="icon-btn" aria-label="Back">
            <ArrowLeft size={20} />
          </button>
          <h2>Add Money to Wallet</h2>
        </div>

        {/* Progress Steps */}
        <div className="progress-steps">
          <div className="step active">
            <span className="step-number">1</span>
            <span className="step-label">Amount</span>
          </div>
          <div className="step-connector" />
          <div className="step">
            <span className="step-number">2</span>
            <span className="step-label">Payment</span>
          </div>
          <div className="step-connector" />
          <div className="step">
            <span className="step-number">3</span>
            <span className="step-label">Confirm</span>
          </div>
        </div>

        {/* Amount Section */}
        <div className="wallet-card">
          <label className="input-label">Enter Amount</label>
          <div className="amount-input-wrapper">
            <span className="currency-symbol">₹</span>
            <input
              type="number"
              placeholder="0.00"
              value={amount}
              onChange={(e) => setAmount(e.target.value)}
              onKeyPress={handleKeyPress}
              min="10"
              step="0.01"
              disabled={loading}
            />
          </div>

          <div className="quick-amounts">
            {quickAmounts.map((val) => (
              <button
                key={val}
                type="button"
                onClick={() => setAmount(val.toString())}
                className={`quick-btn ${amount === val.toString() ? 'selected' : ''}`}
                disabled={loading}
              >
                ₹{val}
              </button>
            ))}
          </div>
          {error && <p className="error-message" role="alert">{error}</p>}
        </div>

        {/* Payment Method */}
        <div className="wallet-card">
          <label className="input-label">Select Payment Method</label>
          <div className="payment-methods">
            {paymentMethods.map((method) => {
              const Icon = method.icon;
              return (
                <button
                  key={method.id}
                  type="button"
                  onClick={() => setPaymentMethod(method.id)}
                  className={`payment-method-btn ${paymentMethod === method.id ? 'selected' : ''}`}
                  disabled={loading}
                >
                  <Icon size={20} />
                  <span>{method.label}</span>
                  {paymentMethod === method.id && <CheckCircle size={16} className="check-icon" />}
                </button>
              );
            })}
          </div>
        </div>

        {/* Summary */}
        {amount && parseFloat(amount) >= 10 && (
          <div className="summary-card">
            <div className="summary-row">
              <span>Amount</span>
              <strong>₹{parseFloat(amount).toFixed(2)}</strong>
            </div>
            <div className="summary-row">
              <span>Convenience Fee</span>
              <strong className="free">Free</strong>
            </div>
            <div className="summary-row total">
              <span>Total Payable</span>
              <strong>₹{parseFloat(amount).toFixed(2)}</strong>
            </div>
          </div>
        )}

        {/* Action Button */}
        <button
          type="button"
          className="primary-btn"
          onClick={handleAddFunds}
          disabled={loading || !amount || parseFloat(amount) < 10}
        >
          {loading ? (
            <>
              <Loader2 className="spin" size={20} />
              <span>Processing Payment...</span>
            </>
          ) : (
            <>
              <span>Pay ₹{amount ? parseFloat(amount).toFixed(2) : '0.00'}</span>
              <ArrowRight size={18} />
            </>
          )}
        </button>

        {/* Security Badge */}
        <div className="security-note">
          <Shield size={14} />
          <span>Your payment is secured with bank-grade encryption</span>
        </div>
      </div>
    </div>
  );
}
